from typing import Dict, List, Optional, Union
from datetime import datetime


class FileExplorerAPI:
    def __init__(self, base_directory: str):
        self.base_directory = os.path.abspath(base_directory)
        if not os.path.exists(self.base_directory):
            os.makedirs(self.base_directory)
    
    def _get_safe_path(self, relative_path: str) -> Optional[str]:
        full_path = os.path.normpath(os.path.join(self.base_directory, relative_path))
        
        if not full_path.startswith(self.base_directory):
            raise ValueError("Access denied: Path traversal detected")
        
        return full_path
    
    def list_directory(self, relative_path: str = "") -> List[Dict[str, Union[str, int, bool]]]:
        full_path = self._get_safe_path(relative_path)
        
        if not os.path.exists(full_path):
            raise FileNotFoundError(f"Directory not found: {relative_path}")
        
        if not os.path.isdir(full_path):
            raise NotADirectoryError(f"Path is not a directory: {relative_path}")
        
        items = []
        for entry in os.listdir(full_path):
            entry_path = os.path.join(full_path, entry)
            is_dir = os.path.isdir(entry_path)
            
            item_info = {
                "name": entry,
                "is_directory": is_dir,
                "path": os.path.normpath(os.path.join(relative_path, entry))
            }
            
            if not is_dir:
                stat_info = os.stat(entry_path)
                item_info["size"] = stat_info.st_size
                item_info["modified"] = datetime.fromtimestamp(stat_info.st_mtime).isoformat()
            
            items.append(item_info)
        
        items.sort(key=lambda x: (not x["is_directory"], x["name"].lower()))
        return items
    
    def get_file_info(self, relative_path: str) -> Dict[str, Union[str, int]]:
        full_path = self._get_safe_path(relative_path)
        
        if not os.path.exists(full_path):
            raise FileNotFoundError(f"File not found: {relative_path}")
        
        if os.path.isdir(full_path):
            raise IsADirectoryError(f"Path is a directory, not a file: {relative_path}")
        
        stat_info = os.stat(full_path)
        mime_type, _ = mimetypes.guess_type(full_path)
        
        return {
            "name": os.path.basename(full_path),
            "path": relative_path,
            "size": stat_info.st_size,
            "created": datetime.fromtimestamp(stat_info.st_ctime).isoformat(),
            "modified": datetime.fromtimestamp(stat_info.st_mtime).isoformat(),
            "mime_type": mime_type or "application/octet-stream",
            "extension": os.path.splitext(full_path)[1]
        }
    
    def download_file(self, relative_path: str) -> bytes:
        full_path = self._get_safe_path(relative_path)
        
        if not os.path.exists(full_path):
            raise FileNotFoundError(f"File not found: {relative_path}")
        
        if os.path.isdir(full_path):
            raise IsADirectoryError(f"Path is a directory, not a file: {relative_path}")
        
        with open(full_path, 'rb') as f:
            return f.read()
    
    def get_file_path(self, relative_path: str) -> str:
        return self._get_safe_path(relative_path)


